const input = $json.body ?? $json;
const data = {
  project_id: input.project_id,
  mission_plan_id: input.mission_plan_id,
  task_count: Number(input.task_count || 0),
  goal: input.goal || 'Mit dem Verkauf moderner Websites an lokale Unternehmen Umsatz erzielen',
  city: input.city || 'Heidelberg',
  target_revenue: Number(input.target_revenue || 500),
  preferred_industries: input.preferred_industries || 'Alle Branchen, die lokal über eine Website Kunden gewinnen können; dynamisch nach Bedarf, Website-Defizit, Kontaktierbarkeit und Auftragswert priorisieren',
  website_style: input.website_style || 'minimalistisch, modern und clean',
  color_direction: input.color_direction || 'modern, minimalistisch und clean; unternehmensspezifisch',
  animation_style: input.animation_style || 'sehr dynamisch und cineastisch mit scrollgebundenen Szenen, maskierten Übergängen und Parallax; Reduced-Motion- und Mobile-Fallback vorsehen',
  key_sections: input.key_sections || 'Unternehmensspezifisch aus Google Maps, bestehender Website und weiteren öffentlichen Informationen ableiten',
  offer_price: Number(input.offer_price || 350),
  offer_min: Number(input.offer_min || 200),
  offer_max: Number(input.offer_max || 500),
  max_leads: Math.min(Number(input.max_leads || 20), 20),
  outreach_channel: input.outreach_channel || 'E-Mail-Entwurf',
  outreach_approval: false,
  crm_spreadsheet_id: input.crm_spreadsheet_id || '1uCKDobkcfjjOOmRUGeUVCwtAW5ddw49Smo7nWz9hysY',
  reference_folder_id: input.reference_folder_id || '1O-oENk03wkd6DcnWBVeiKBGocb4MQ5VL',
  reference_video_ids: input.reference_video_ids || ['1xRcjUjZmaCYzU0-5dKdAAfzimvIssImn', '1UjVzKF4wIWt1eMBBxlguh_EoOwKPaWwv'],
};
const required = ['preferred_industries', 'website_style', 'animation_style', 'key_sections', 'outreach_channel'];
const missing = required.filter((key) => !data[key]);
const questionMap = {
  preferred_industries: 'Welche Branchen sollen priorisiert werden?',
  website_style: 'Wie soll die Website wirken?',
  animation_style: 'Wie intensiv sollen Scroll-Animationen sein?',
  key_sections: 'Welche Bereiche soll die Website enthalten?',
  outreach_channel: 'Welcher Kontaktkanal ist erlaubt?',
};
const questions = missing.map((key) => ({ field: key, question: questionMap[key] }));
const missionGoal = `${data.goal}. Region: ${data.city}. Zielumsatz: ${data.target_revenue} EUR, ohne Umsatzgarantie. Branchenoffen nach Kundengewinnungspotenzial priorisieren: ${data.preferred_industries}. Website-Stil: ${data.website_style}; Farbwelt: ${data.color_direction}; Scroll-Animationen: ${data.animation_style}. Bereiche: ${data.key_sections}. Starterangebot: ${data.offer_min}-${data.offer_max} EUR, Richtwert ${data.offer_price} EUR. Maximal ${data.max_leads} sorgfältig qualifizierte Leads. Kontaktkanal: ${data.outreach_channel}; niemals automatisch versenden. Designreferenzen: Drive-Ordner ${data.reference_folder_id}, Videos ${data.reference_video_ids.join(', ')}. Datenschutz, Impressum, Quellen, Opt-out und Audit-Trail beachten.`;
return [{ json: { ready: missing.length === 0, questions, data, mission_goal: missionGoal } }];

const input = $json.body ?? $json;
if (input.send === true) throw new Error('Automatischer E-Mail-Versand ist gesperrt.');
if (!input.lead?.id || !input.lead?.name) throw new Error('Lead ist unvollständig.');
if (!input.draft?.to || !input.draft?.subject || !input.draft?.body) throw new Error('E-Mail-Entwurf ist unvollständig.');
return [{ json: { ...input, send: false, approval_status: 'pending' } }];

const context = $('Project Delivery Webhook').first().json.body;
const matches = $input.all().filter(item => item.json?.id);
const name = $('Project Delivery Webhook').first().json.body.project.name;
const exact = matches.find(item => item.json.name === name);
const configured = context.folders?.project || '';
return [{ json: { ...context, folder_id: configured || exact?.json.id || '', folder_name: name } }];

const context = $('Select Project Folder').first().json;
const folderId = $json.id || context.folder_id;
return [{ json: { ...context, folders: { ...(context.folders || {}), project: folderId } } }];

const context = $('Finalize Project Folder').first().json;
const matches = $input.all().filter(item => item.json?.id);
const name = "CRM & Leads";
const exact = matches.find(item => item.json.name === name);
const configured = context.folders?.crm || '';
return [{ json: { ...context, folder_id: configured || exact?.json.id || '', folder_name: name } }];

const context = $('Select CRM & Leads Folder').first().json;
const folderId = $json.id || context.folder_id;
return [{ json: { ...context, folders: { ...(context.folders || {}), crm: folderId } } }];

const context = $('Finalize CRM & Leads Folder').first().json;
const matches = $input.all().filter(item => item.json?.id);
const name = "Websites & Angebote";
const exact = matches.find(item => item.json.name === name);
const configured = context.folders?.websites || '';
return [{ json: { ...context, folder_id: configured || exact?.json.id || '', folder_name: name } }];

const context = $('Select Websites & Angebote Folder').first().json;
const folderId = $json.id || context.folder_id;
return [{ json: { ...context, folders: { ...(context.folders || {}), websites: folderId } } }];

const context = $('Finalize Websites & Angebote Folder').first().json;
const matches = $input.all().filter(item => item.json?.id);
const name = "Berichte & Ergebnisse";
const exact = matches.find(item => item.json.name === name);
const configured = context.folders?.results || '';
return [{ json: { ...context, folder_id: configured || exact?.json.id || '', folder_name: name } }];

const context = $('Select Berichte & Ergebnisse Folder').first().json;
const folderId = $json.id || context.folder_id;
return [{ json: { ...context, folders: { ...(context.folders || {}), results: folderId } } }];

const context = $('Finalize Berichte & Ergebnisse Folder').first().json;
const name = `Leads – ${context.project.name}`;
const exact = $input.all().find(item => item.json?.id && item.json.name === name);
return [{ json: { ...context, crm_sheet_id: exact?.json.id || '', crm_sheet_name: name } }];

const context = $('Select Project CRM Sheet').first().json;
const id = $json.id || context.crm_sheet_id;
return [{ json: { ...context, crm_sheet_id: id, crm_sheet_url: id ? `https://docs.google.com/spreadsheets/d/${id}` : '' } }];

const input = $('Finalize Project CRM Sheet').first().json;
const artifacts = Array.isArray(input.artifacts) ? input.artifacts : [];
return artifacts.map((artifact) => {
  const text = `${artifact.name} ${artifact.artifact_type} ${artifact.media_type}`.toLowerCase();
  let bucket = 'results';
  if (/lead|crm|kontakt|e-mail|email/.test(text)) bucket = 'crm';
  else if (/website|angebot|html|css|javascript|typescript/.test(text)) bucket = 'websites';
  return {
    json: { artifact_key: artifact.key, artifact_name: artifact.name, project: input.project, spreadsheet_id: input.spreadsheet_id, folders: input.folders, target_folder_id: input.folders[bucket] },
    binary: { data: { data: artifact.content_base64, mimeType: artifact.media_type || 'application/octet-stream', fileName: artifact.name } },
    pairedItem: { item: 0 }
  };
});

const uploaded = $input.all();
const source = $('Prepare Routed Delivery Files').all();
const context = $('Finalize Project CRM Sheet').first().json;
const artifactUrls = {};
for (let i = 0; i < uploaded.length; i++) { const key = source[i]?.json.artifact_key; const id = uploaded[i]?.json.id; if (key && id) artifactUrls[key] = `https://drive.google.com/open?id=${id}`; }
return [{ json: { status: 'synced', project: context.project, spreadsheet_id: context.spreadsheet_id, crm_sheet_url: context.crm_sheet_url, artifact_count: uploaded.length, artifact_urls: artifactUrls, folders: context.folders, project_url: `https://drive.google.com/drive/folders/${context.folders.project}`, websites_url: `https://drive.google.com/drive/folders/${context.folders.websites}` } }];
